diff --git a/test/esModule-option.test.js b/test/esModule-option.test.js
new file mode 100644
index 0000000..ed7ab6a
--- /dev/null
+++ b/test/esModule-option.test.js
@@ -0,0 +1,52 @@
+import {
+  compile,
+  execute,
+  getCompiler,
+  normalizeErrors,
+  readAsset,
+} from './helpers';
+
+describe('"esModule" option', () => {
+  it('should work without value', async () => {
+    const compiler = getCompiler('simple.js');
+    const stats = await compile(compiler);
+
+    expect(
+      execute(readAsset('main.bundle.js', compiler, stats))
+    ).toMatchSnapshot('result');
+    expect(normalizeErrors(stats.compilation.warnings)).toMatchSnapshot(
+      'warnings'
+    );
+    expect(normalizeErrors(stats.compilation.errors)).toMatchSnapshot('errors');
+  });
+
+  it('should work with "Boolean" value equal "true"', async () => {
+    const compiler = getCompiler('simple.js', {
+      esModule: true,
+    });
+    const stats = await compile(compiler);
+
+    expect(
+      execute(readAsset('main.bundle.js', compiler, stats))
+    ).toMatchSnapshot('result');
+    expect(normalizeErrors(stats.compilation.warnings)).toMatchSnapshot(
+      'warnings'
+    );
+    expect(normalizeErrors(stats.compilation.errors)).toMatchSnapshot('errors');
+  });
+
+  it('should work with "Boolean" value equal "false"', async () => {
+    const compiler = getCompiler('simple.js', {
+      esModule: false,
+    });
+    const stats = await compile(compiler);
+
+    expect(
+      execute(readAsset('main.bundle.js', compiler, stats))
+    ).toMatchSnapshot('result');
+    expect(normalizeErrors(stats.compilation.warnings)).toMatchSnapshot(
+      'warnings'
+    );
+    expect(normalizeErrors(stats.compilation.errors)).toMatchSnapshot('errors');
+  });
+});

diff --git a/test/loader.test.js b/test/loader.test.js
index 0086268..ae3425f 100644
--- a/test/loader.test.js
+++ b/test/loader.test.js
@@ -1,16 +1,66 @@
-import { webpack } from './helpers';
+import {
+  compile,
+  execute,
+  getCompiler,
+  normalizeErrors,
+  readAsset,
+} from './helpers';

 describe('loader', () => {
-  it('should works', async () => {
-    const stats = await webpack('basic.js');
-    const { modules } = stats.toJson();
-    const [inline, , file, separator] = modules;
+  it('should work', async () => {
+    const compiler = getCompiler('simple.js');
+    const stats = await compile(compiler);

-    expect(inline.source).toMatchSnapshot('inline');
-    expect(file.source).toMatchSnapshot('file');
-    expect(separator.source).toMatchSnapshot('separator');
+    expect(
+      execute(readAsset('main.bundle.js', compiler, stats))
+    ).toMatchSnapshot('result');
+    expect(Object.keys(stats.compilation.assets)).toMatchSnapshot('assets');
+    expect(normalizeErrors(stats.compilation.warnings)).toMatchSnapshot(
+      'warnings'
+    );
+    expect(normalizeErrors(stats.compilation.errors)).toMatchSnapshot('errors');
+  });
+
+  it('should work with inline loader', async () => {
+    const compiler = getCompiler('inline.js');
+    const stats = await compile(compiler);
+
+    expect(
+      execute(readAsset('main.bundle.js', compiler, stats))
+    ).toMatchSnapshot('result');
+    expect(Object.keys(stats.compilation.assets)).toMatchSnapshot('assets');
+    expect(normalizeErrors(stats.compilation.warnings)).toMatchSnapshot(
+      'warnings'
+    );
+    expect(normalizeErrors(stats.compilation.errors)).toMatchSnapshot('errors');
+  });
+
+  it('should work with "ModuleConcatenationPlugin" plugin', async () => {
+    const compiler = getCompiler(
+      'simple.js',
+      {},
+      {
+        mode: 'production',
+        optimization: {
+          minimize: false,
+        },
+      }
+    );
+    const stats = await compile(compiler);
+
+    expect(
+      execute(readAsset('main.bundle.js', compiler, stats))
+    ).toMatchSnapshot('result');
+    expect(Object.keys(stats.compilation.assets)).toMatchSnapshot('assets');
+    expect(normalizeErrors(stats.compilation.warnings)).toMatchSnapshot(
+      'warnings'
+    );
+    expect(normalizeErrors(stats.compilation.errors)).toMatchSnapshot('errors');

-    expect(stats.compilation.warnings).toMatchSnapshot('warnings');
-    expect(stats.compilation.errors).toMatchSnapshot('errors');
+    if (stats.compilation.modules.size) {
+      expect(stats.compilation.modules.size).toBe(1);
+    } else {
+      expect(stats.compilation.modules.length).toBe(1);
+    }
   });
 });

diff --git a/test/validate-options.test.js b/test/validate-options.test.js
index e31c6bd..d794838 100644
--- a/test/validate-options.test.js
+++ b/test/validate-options.test.js
@@ -1,18 +1,60 @@
-import loader from '../src';
-
-it('validate options', () => {
-  const validate = (options) =>
-    loader.call(
-      Object.assign(
-        {},
-        {
-          query: options,
+import { getCompiler, compile } from './helpers';
+
+describe('validate options', () => {
+  const tests = {
+    esModule: {
+      success: [true, false],
+      failure: ['true'],
+    },
+    unknown: {
+      success: [],
+      failure: [1, true, false, 'test', /test/, [], {}, { foo: 'bar' }],
+    },
+  };
+
+  function stringifyValue(value) {
+    if (
+      Array.isArray(value) ||
+      (value && typeof value === 'object' && value.constructor === Object)
+    ) {
+      return JSON.stringify(value);
+    }
+
+    return value;
+  }
+
+  async function createTestCase(key, value, type) {
+    it(`should ${
+      type === 'success' ? 'successfully validate' : 'throw an error on'
+    } the "${key}" option with "${stringifyValue(value)}" value`, async () => {
+      const compiler = getCompiler('simple.js', { [key]: value });
+
+      let stats;
+
+      try {
+        stats = await compile(compiler);
+      } finally {
+        if (type === 'success') {
+          expect(stats.hasErrors()).toBe(false);
+        } else if (type === 'failure') {
+          const {
+            compilation: { errors },
+          } = stats;
+
+          expect(errors).toHaveLength(1);
+          expect(() => {
+            throw new Error(errors[0].error.message);
+          }).toThrowErrorMatchingSnapshot();
         }
-      ),
-      'Text'
-    );
+      }
+    });
+  }

-  expect(() => validate({})).not.toThrow();
-  expect(() => validate(true)).not.toThrow();
-  expect(() => validate({ unknown: true })).toThrowErrorMatchingSnapshot();
+  for (const [key, values] of Object.entries(tests)) {
+    for (const type of Object.keys(values)) {
+      for (const value of values[type]) {
+        createTestCase(key, value, type);
+      }
+    }
+  }
 });

